<template>
  <a-layout style="min-height: 100vh; background: #fff;">
    <!-- 左侧：文档目录树 -->
    <a-layout-sider width="250" style="background: #fff; border-right: 1px solid #f0f0f0;">
      <a-menu
        mode="inline"
        style="height: 100%; border-right: 0;"
        :selected-keys="selectedKeys"
        :default-open-keys="defaultOpenKeys"
        @click="handleMenuClick"
      >
        <a-menu-item key="welcome">
          <FileTextOutlined />
          <span>文档目录</span>
        </a-menu-item>
        <a-sub-menu v-for="item in level1" :key="item.id">
          <template #title>
            <span><FolderOutlined />{{ item.name }}</span>
          </template>
          <a-menu-item v-for="child in item.children" :key="child.id">
            <FileOutlined /><span>{{ child.name }}</span>
          </a-menu-item>
        </a-sub-menu>
      </a-menu>
    </a-layout-sider>

    <!-- 右侧：文档内容 -->
    <a-layout-content style="padding: 24px;">
      <div v-if="isShowWelcome" style="text-align: center; padding: 100px 0; color: #999;">
        <h2>请从左侧选择要查看的文档</h2>
      </div>

      <div v-else>
        <!-- 文档标题和点赞 -->
        <div style="display: flex; align-items: center; justify-content: space-between; margin-bottom: 16px;">
          <h2 style="margin: 0;">{{ currentDoc.name }}</h2>
          <div>
            <span style="margin-right: 16px; color: #666;">
              <LikeOutlined /> {{ currentDoc.voteCount || 0 }}
            </span>
            <a-button type="primary" @click="handleVote" :disabled="voted">
              <template #icon><LikeOutlined /></template>
              点赞
            </a-button>
          </div>
        </div>

        <div class="doc-content" v-html="docContent"></div>
      </div>
    </a-layout-content>
  </a-layout>
</template>

<script setup>
import { ref, onMounted } from 'vue'
import { useRoute } from 'vue-router'
import axios from 'axios'
import { message } from 'ant-design-vue'
import { FileTextOutlined, FolderOutlined, FileOutlined, LikeOutlined } from '@ant-design/icons-vue'

const route = useRoute()

const level1 = ref([])
const selectedKeys = ref(['welcome'])
const defaultOpenKeys = ref([])
const isShowWelcome = ref(true)
const docContent = ref('')
const currentDoc = ref({
  id: null,
  name: '',
  voteCount: 0
})
const voted = ref(false) // 简单防止重复点击（生产环境需结合后端校验）

// 树形结构构建
const buildTree = (list, parentId = 0) => {
  const pid = String(parentId)
  return list
    .filter(item => String(item.parent) === pid)
    .map(item => ({
      ...item,
      children: buildTree(list, item.id)
    }))
}

// 根据 ID 查找文档名称
const findDocName = (id, list) => {
  for (const item of list) {
    if (String(item.id) === String(id)) return item.name
    if (item.children) {
      const name = findDocName(id, item.children)
      if (name) return name
    }
  }
  return ''
}

// 加载文档目录
const loadDocs = () => {
  const ebookId = route.query.ebookId
  if (!ebookId) {
    message.warning('未指定电子书ID')
    return
  }

  axios.get(`/doc/all/${ebookId}`)
    .then((resp) => {
      const data = resp.data
      if (data.success) {
        level1.value = buildTree(data.content || [], 0)
        defaultOpenKeys.value = level1.value.map(item => String(item.id))
      } else {
        message.error(data.message || '加载文档目录失败')
      }
    })
    .catch(() => {
      message.error('加载文档目录失败')
    })
}

// 点击文档菜单
const handleMenuClick = ({ key }) => {
  selectedKeys.value = [key]

  if (key === 'welcome') {
    isShowWelcome.value = true
    docContent.value = ''
    currentDoc.value = { id: null, name: '', voteCount: 0 }
    return
  }

  isShowWelcome.value = false
  const docId = key
  const docName = findDocName(key, level1.value)

  // 先获取文档基本信息（含投票数）
  axios.get(`/doc/info/${docId}`)
    .then((resp) => {
      const data = resp.data
      if (data.success) {
        currentDoc.value = {
          id: docId,
          name: docName,
          voteCount: data.content.voteCount || 0
        }
        voted.value = false
      } else {
        // 若获取失败，仍显示名称，投票数默认为0
        currentDoc.value = { id: docId, name: docName, voteCount: 0 }
      }
    })
    .catch(() => {
      // 接口不可用，仅显示名称
      currentDoc.value = { id: docId, name: docName, voteCount: 0 }
    })

  // 查询文档内容
  axios.get(`/content/findContent/${docId}`)
    .then((resp) => {
      const data = resp.data
      if (data.success && data.content) {
        docContent.value = data.content
      } else {
        docContent.value = '<p style="color:#999">暂无内容</p>'
      }
    })
    .catch(() => {
      docContent.value = '<p style="color:#999">加载内容失败</p>'
    })
}

// 点赞
const handleVote = () => {
  if (voted.value) {
    message.warning('您已点赞过')
    return
  }
  if (!currentDoc.value.id) return

  axios.get(`/doc/vote/${currentDoc.value.id}`)
    .then((resp) => {
      const data = resp.data
      if (data.success) {
        currentDoc.value.voteCount++
        voted.value = true
        message.success('点赞成功！')
      } else {
        message.error(data.message || '点赞失败')
      }
    })
    .catch(() => {
      message.error('点赞失败，请重试')
    })
}

onMounted(() => {
  loadDocs()
})
</script>

<style scoped>
.doc-content {
  padding: 16px;
  border: 1px solid #f0f0f0;
  border-radius: 4px;
  min-height: 400px;
  background: #fff;
  line-height: 1.8;
}
</style>
